def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(1, 5):
                for b in range(1, 6):
                    term = np.tanh((ratio - 7) * a / (b + 0.5)) + np.sin(ratio * b * 2.3) ** 3
                    priority += term * np.exp(-a * 0.3) / (b + 1)
            if int(ratio) % 2 == 0:
                priority += np.cosh(ratio) * 7
            else:
                priority -= np.sinh(ratio / 2) * 5
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 8.5
            else:
                priority -= np.exp(-ratio) * 6
        elif 5 < ratio <= 8:
            acc = 0
            for c in range(3, 15):
                acc += ((ratio - 5) ** c) * np.cos(ratio * c * 1.5) / (c * 1.2)
            priority = acc * np.sin(ratio * 3) - np.log(ratio) * 4 + np.tanh(5 - ratio) * 3
            for d in range(1, 4):
                if (i + d) % 2 == 1:
                    priority += np.sin(ratio * d * i) * 0.4
                else:
                    priority -= np.cos(ratio * d * i) * 0.4
        elif 2 < ratio <= 5:
            temp_sum = 0
            for e in range(1, 20):
                val = ((ratio - 2) ** e) / (e ** 1.3 + 0.7) * np.cos(e * ratio * 2)
                temp_sum += val
            priority = np.tanh(temp_sum) * 9 - np.sqrt(ratio) * 5
            if bin_cap < item * 1.2:
                priority += np.sin(i * ratio) * 4
            else:
                priority -= np.cos(i * ratio) * 3.5
            for f in range(1, 6):
                priority += np.sin(f * ratio * i) * ((ratio - 2) ** f) / (f * 2)
        elif 1 < ratio <= 2:
            val_sum = 0
            for g in range(1, 12):
                pow_term = ((2 - ratio) ** g) / (g * 2.1)
                trig = np.cos(g * ratio * 3)
                val_sum += pow_term * trig
            priority = val_sum + np.log1p(bin_cap) * 7 - np.tanh(2 - ratio) * 5
            if (i * int(item)) % 5 == 0:
                priority += np.exp(-ratio) * 6
            else:
                priority -= np.exp(-ratio / 2) * 4
        elif 0.5 <= ratio < 1:
            base = 0
            for h in range(1, 25):
                decay = ((1 - ratio) ** h) / (h * 1.5 + 0.2)
                base += decay * np.sin(h * item * 1.7)
            priority = base * np.cos(ratio * 3) + np.tanh(bin_cap / (item + 1)) * 8
            if bin_cap > item:
                priority -= np.sqrt(bin_cap - item) * 5
            else:
                priority += np.sqrt(item - bin_cap) * 5
            for j in range(1, 8):
                if (i + j * 2) % 3 == 0:
                    priority += np.sin(ratio * j * i) * 0.5
                else:
                    priority -= np.cos(ratio * j * i) * 0.5
        elif 0.1 <= ratio < 0.5:
            score = 0
            for k in range(1, 18):
                score += ((0.5 - ratio) ** k) / (k * 2.2) * np.cos(k * ratio * 4)
            priority = score / (bin_cap + 1) * 5 + np.log1p(item / (bin_cap + 0.1)) * 7
            if (i + int(item * 2)) % 6 == 0:
                priority *= 1.8
            else:
                priority /= 1.8
            if bin_cap < item * 0.2:
                priority += np.exp(-bin_cap) * 10
            else:
                priority -= np.exp(-ratio * 3) * 7
        else:
            s = 0
            for l in range(1, 15):
                s += ((0.1 - ratio) ** l) / (l * 3) * np.sin(l * item * 1.3)
            priority = s + 3 / (bin_cap + 2)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for m in range(1, 10):
                priority += ((0.1 - ratio) ** m) / (m * 9) * np.cos(item * m * 1.1)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
